import 'package:bookly/Feature/Home/domain/entities/book_entities.dart';import 'package:dartz/dartz.dart';import 'package:dio/dio.dart';import '../../../../Core/Models/book_model.dart';import '../../../../Core/Utils/Errors/failure.dart';import '../../../../Core/network/dio.dart';import '../../data/repositories/similar_books_repo.dart';class SimilarBooksRepoImpl extends SimilarBooksRepo {  @override  Future<Either<Failure, List<BookEntities>>> fetchSimilarBooks(      {required String category}) async {    try {      var data = await DioHelper.getData(          path: 'volumes?Sorting=relevance&Filtering=full&q=$category');      List<BookModel> books = [];      for (final item in data.data["item"]) {        books.add(BookModel.fromJson(item));      }      return right(books);    } catch (e) {      if (e is DioException) {        return left(ServerFailure.fromDioError(e));      } else {        return left(ServerFailure.fromResponse(e.hashCode, e));      }    }  }}